module barrel_shifter #(parameter DATA_WIDTH=16, parameter SHIFT_BITS_WIDTH=4)(
	input [DATA_WIDTH-1:0] data_in,
	input [SHIFT_BITS_WIDTH-1:0] shift_bits,
	input rotate_left_right,
	output reg [DATA_WIDTH-1:0] data_out
);

always @(*) begin
	if (rotate_left_right == 1) begin
		// Perform a rotate operation
		reg [DATA_WIDTH-1:0] rotated_data;

		for (int i=0; i<DATA_WIDTH; i++) begin
			rotated_data[i] = data_in[(i+shift_bits)%DATA_WIDTH];
		}

		data_out = rotated_data;
	end else begin
		// Perform a left or right shift
		case (shift_bits)
			0: data_out = data_in;
			default: data_out = (rotate_left_right == 0)? {data_in[DATA_WIDTH-1:shift_bits], data_in[DATA_WIDTH-shift_bits-1:0]} : {data_in[shift_bits-1:0], data_in[DATA_WIDTH-1:shift_bits]};
		endcase
	end
end

endmodule

input.rtl/barrel_shifter.sv:
module barrel_shifter #(
    parameter data_width = 16,      // Change data_width to 16
    parameter shift_bits_width = 4  // Update shift_bits_width to handle shifts for 16-bit width
)(
    input [data_width-1:0] data_in,
    input [shift_bits_width-1:0] shift_bits,
    input left_right,               // 1: left shift, 0: right shift
    input rotate_left_right,        // 1: rotate, 0: shift
    input arithmetic_shift,         // 1: arithmetic shift, 0: logical shift
    output reg [data_width-1:0] data_out
);

always @(*) begin
    if (rotate_left_right) begin
        // Rotation logic
        if (left_right)
            data_out = (data_in << shift_bits) | (data_in >> (data_width - shift_bits)); // Rotate left
        else
            data_out = (data_in >> shift_bits) | (data_in << (data_width - shift_bits)); // Rotate right
    end else begin
        // Shift logic
        if (left_right)
            data_out = data_in << shift_bits;  // Left shift
        else if (arithmetic_shift)
            // Arithmetic right shift: explicitly sign-extend data_in to ensure the MSB (sign bit) is preserved
            data_out = $signed(data_in) >>> shift_bits;
        else
            data_out = data_in >> shift_bits;  // Logical right shift
    end
end

endmodule

output.rtl/barrel_shifter.sv:
module barrel_shifter #(
    parameter data_width = 16,      // Change data_width to 16
    parameter shift_bits_width = 4  // Update shift_bits_width to handle shifts for 16-bit width
)(
    input [data_width-1:0] data_in,
    input [shift_bits_width-1:0] shift_bits,
    input left_right,               // 1: left shift, 0: right shift
    input rotate_left_right,        // 1: rotate, 0: shift
    input arithmetic_shift,         // 1: arithmetic shift, 0: logical shift
    output reg [data_width-1:0] data_out
);

// Define error signal
wire error;
assign error = ~((left_right && rotate_left_right) || (!left_right &&!rotate_left_right));

// Calculate the number of shifts needed based on the mode and shift value
reg [2:0] shift_count;
always @(posedge clk) begin
    case (mode)
        3'b000: shift_count <= shift_bits;
        3'b001: begin
            shift_count <= (shift_bits == 0)? 0 : {shift_bits[data_width-1], shift_bits};
        end
        3'b010: begin
            shift_count <= (shift_bits == 0)? 0 : shift_bits;
        end
        3'b011: begin
            shift_count <= (shift_bits == 0)? 0 : shift_bits;
        end
        3'b100: begin
            shift_count <= (shift_bits == 0)? 0 : shift_bits;
        end
        default: shift_count <= 0;
    endcase
end

// Apply the selected operation based on the mode
always @(posedge clk) begin
    unique case (mode)
        3'b000: data_out <= data_in << shift_count;
        3'b001: data_out <= ($signed(data_in) >>> shift_count);
        3'b010: data_out <= {<<{shift_count}};
        3'b011: begin
            reg [data_width-1:0] temp;
            temp = data_in;
            for (int i = 0; i < shift_count; i++) begin
                temp[i] = mask[i];
            end
            data_out <= temp;
        end
        3'b100: begin
            reg [data_width-1:0] temp;
            temp = data_in;
            for (int i = shift_count-1; i >= 0; i--) begin
                temp[i] ^= mask[i];
            end
            data_out <= temp;
        end
        default: data_out <= 0;
    endcase
end

endmodule

