module pseudoRandGenerator_ca (
    input  logic       clock,    // Clock input
    input  logic       reset,    // Active-high synchronous Reset
    input  logic [15:0] CA_seed,  // 16-bit Cellular Automata seed
    output logic [15:0] CA_out    // 16-bit Cellular Automata output
);

    logic q1, q2, q3, q4, q5, q6, q7, q8;
    logic q9, q10, q11, q12, q13, q14, q15, q16;

    always @(posedge clock) begin
        if (reset) begin
            // Initialize the CA-based shift register with the provided seed value
            q1 <= CA_seed[15];
            q2 <= CA_seed[14];
            q3 <= CA_seed[13];
            q4 <= CA_seed[12];
            q5 <= CA_seed[11];
            q6 <= CA_seed[10];
            q7 <= CA_seed[9];
            q8 <= CA_seed[8];

            q9 <= CA_seed[7];
            q10 <= CA_seed[6];
            q11 <= CA_seed[5];
            q12 <= CA_seed[4];
            q13 <= CA_seed[3];
            q14 <= CA_seed[2];
            q15 <= CA_seed[1];
            q16 <= CA_seed[0];
        end else begin
            // Calculate the new state of each bit in the CA-based shift register based on rules 90 and 150
            q1 <= q2;
            q2 <= q3;
            q3 <= q4;
            q4 <= q5;
            q5 <= q6;
            q6 <= q7;
            q7 <= q8;
            q8 <= ~q9 & q10 | q9 & ~q10;

            q9 <= q10;
            q10 <= q11;
            q11 <= q12;
            q12 <= q13;
            q13 <= q14;
            q14 <= q15;
            q15 <= q16;
            q16 <= ~q1 & q2 | q1 & ~q2;
        end
    end

    assign CA_out = {q16, q15, q14, q13, q12, q11, q10, q9};

endmodule

input.rtl/pseudoRandGenerator_ca.sv:
module pseudoRandGenerator_ca (
    input  logic       clock,    // Clock input
    input  logic       reset,    // Active-high synchronous Reset
    input  logic [15:0] CA_seed,  // 16-bit Cellular Automata seed
    output logic [15:0] CA_out    // 16-bit Cellular Automata output
);

    logic q1, q2, q3, q4, q5, q6, q7, q8;
    logic q9, q10, q11, q12, q13, q14, q15, q16;

    assign q1  = CA_out[14];                             
    assign q2  = CA_out[15] ^ CA_out[13];                
    assign q3  = CA_out[14] ^ CA_out[13] ^ CA_out[12];   
    assign q4  = CA_out[13] ^ CA_out[11];                
    assign q5  = CA_out[12] ^ CA_out[11] ^ CA_out[10];   
    assign q6  = CA_out[11] ^ CA_out[9];                 
    assign q7  = CA_out[10] ^ CA_out[9] ^ CA_out[8];     
    assign q8  = CA_out[9] ^ CA_out[7];                  
    assign q9  = CA_out[8] ^ CA_out[7] ^ CA_out[6];      
    assign q10 = CA_out[7] ^ CA_out[5];                  
    assign q11 = CA_out[6] ^ CA_out[5] ^ CA_out[4];      
    assign q12 = CA_out[5] ^ CA_out[3];                  
    assign q13 = CA_out[4] ^ CA_out[3] ^ CA_out[2];      
    assign q14 = CA_out[3] ^ CA_out[1];                  
    assign q15 = CA_out[2] ^ CA_out[1] ^ CA_out[0];      
    assign q16 = CA_out[1];                              

    always_ff @(posedge clock) begin
        if (reset) begin
            CA_out <= CA_seed;
        end else begin
            CA_out[20] <= q6;
            CA_out[19] <= q5;
            CA_out[18] <= q4;
            CA_out[17] <= q3;
            CA_out[16] <= q2;
            CA_out[15] <= q1;
            CA_out[14] <= q2;
            CA_out[13] <= q3;
            CA_out[12] <= q4;
            CA_out[11] <= q5;
            CA_out[10] <= q6;
            CA_out[9]  <= q7;
            CA_out[8]  <= q8;
            CA_out[7]  <= q9;
            CA_out[6]  <= q10;
            CA_out[5]  <= q11;
            CA_out[4]  <= q12;
            CA_out[3]  <= q13;
            CA_out[2]  <= q14;
            CA_out[1]  <= q15;
            CA_out[0]  <= q16;
        end
    end

endmodule

output.rtl/clock_divider.sv:
module clock_divider (
    input wire clk,
    input wire rst_n,
    input wire [1:0] sel,
    output reg clk_out
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        clk_out <= 1'b0;
    end else begin
        case (sel)
            2'b00: clk_out <= clk / 2;
            2'b01: clk_out <= clk / 4;
            2'b10: clk_out <= clk / 8;
            default: clk_out <= 1'b0; // Out-of-range value, hold low
        endcase
    end
end

endmodule

output.rtl/clock_jitter_detection_module.sv:
module clock_jitter_detection_module #(
    parameter JITTER_THRESHOLD = 5    // Threshold (in clock cycles) for detecting jitter
)(
    input logic clk,               // Input clock
    input logic system_clk,        // Input system clock
    input logic rst,               // Active high reset
    output logic jitter_detected   // Output flag indicating jitter detection
);

    // Internal signals
    logic [31:0] edge_count, edge_count_r;   // Counters to measure time between rising edges
    logic prev_system_clk;                   // To store the previous clock state (rising edge detection)
    logic edge_detected;                     // Flag for detecting rising edges
    logic start_counter;

    // Rising edge detection logic (detects when clock transitions from 0 to 1)
    always @(posedge clk) begin
        if (rst) begin
            // Initialize counters, edge detection, and jitter detection on reset
            edge_count <= 0;
            prev_system_clk <= 1;
            edge_detected <= 0;
            start_counter <= 1;
            jitter_detected <= 0;
        end else begin
            // Detect rising edge transitions of system_clk
            if (!prev_system_clk && system_clk) begin
                edge_count <= 0;
                start_counter <= 1;
                edge_detected <= 1;
            end else if (start_counter) begin
                edge_count <= edge_count + 1;
                start_counter <= 0;
            end

            // Compare edge_count_r with JITTER_THRESHOLD and detect jitter
            if (edge_detected && (edge_count > JITTER_THRESHOLD)) begin
                jitter_detected <= 1;
            end

            // Store previous system clock state for next iteration
            prev_system_clk <= system_clk;
        end
    end

endmodule

input.rtl/coffee_machine.sv:
module coffee_machine #(
    parameter NBW_DLY    = 'd5,
    parameter NBW_BEANS  = 'd2,
    parameter NS_BEANS   = 'd4,
    parameter NS_OP      = 'd3, // Fixed
    parameter NS_SENSOR  = 'd4  // Fixed
) (
    input  logic                 clk,
    input  logic                 rst_async_n,
    input  logic [NBW_DLY-1:0]   i_grind_delay,
    input  logic [NBW_DLY-1:0]   i_heat_delay,
    input  logic [NBW_DLY-1:0]   i_pour_delay,
    input  logic [NBW_BEANS-1:0] i_bean_sel,
    input  logic [NS_OP-1:0]     i_operation_sel,
    input  logic                 i_start,
    input  logic [NS_SENSOR-1:0] i_sensor,
    output logic [NS_BEANS-1:0]  o_bean_sel,
    output logic                 o_grind_beans,
    output logic                 o_use_powder,
    output logic                 o_heat_water,
    output logic                 o_pour_coffee,
    output logic                 o_error
);

// Fixed delays (bean selection and powder usage)
localparam SEL_CYCLES    = 'd3;
localparam POWDER_CYCLES = 'd2;

typedef enum logic [2:0] {
    IDLE     = 3'b000,
    BEAN_SEL = 3'b001,
    GRIND    = 3'b011,
    POWDER   = 3'b111,
    HEAT     = 3'b110,
    POUR     = 3'b100
} state_t;

// ----------------------------------------
// - Wires/Registers creation
// ----------------------------------------
state_t state_ff, state_nx;
logic [NBW_DLY:0]     counter_ff, counter_nx;
logic [NBW_DLY-1:0]   grind_delay_ff, heat_delay_ff, pour_delay_ff;
logic [NS_OP-1:0]     operation_sel_ff;
logic [NBW_BEANS-1:0] bean_sel_in_ff;
logic                 start_ff;

// Output assignment (error conditions)
always_comb begin : error_logic
    if(state_ff == IDLE) begin
        o_error = (i_sensor[0] | i_sensor[3]) | (&i_operation_sel[2:1]) | (i_operation_sel[1] & i_sensor[1]) | ((i_operation_sel[2] || i_operation_sel[0]) & i_sensor[2]);
    end else begin
        o_error = i_sensor[3];
    end
end

// ----------------------------------------
// - Registers
// ----------------------------------------
always_ff @(posedge clk) begin : data_regs
    start_ff <= i_start & ~(i_sensor[0] | i_sensor[3]) & (|i_operation_sel[2:1]) & ~(i_operation_sel[1] & i_sensor[1]) & ~((i_operation_sel == 3'b100 || i_operation_sel == 3'b001) & i_sensor[2]);

    if(i_start && state_ff == IDLE) begin
        operation_sel_ff <= i_operation_sel;
        grind_delay_ff   <= i_grind_delay;
        heat_delay_ff    <= i_heat_delay;
        pour_delay_ff    <= i_pour_delay;
        bean_sel_in_ff   <= i_bean_sel;
    end

    counter_ff      <= counter_nx;
end

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        state_ff <= IDLE;
    end else begin
        state_ff <= state_nx;
    end
end

// ----------------------------------------
// - FSM update
// ----------------------------------------
always_comb begin
    case(state_ff)
        IDLE: begin
            counter_nx = 0;

            if(start_ff) begin
                if(~(|i_operation_sel[2:1])) begin
                    state_nx = HEAT;
                end else if(i_operation_sel[1]) begin
                    state_nx = BEAN_SEL;
                end else if(i_operation_sel[0]) begin
                    state_nx = POUR;
                end else begin
                    state_nx = POWDER;
                end
            end else begin
                state_nx = IDLE;
            end
        end
        BEAN_SEL: begin
            if(counter_ff >= SEL_CYCLES) begin
                counter_nx = 0;
                state_nx   = GRIND;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = BEAN_SEL;
            end
        end
        GRIND: begin
            if(counter_ff >= grind_delay_ff) begin
                counter_nx = 0;
                if(operation_sel_ff[0]) begin
                    state_nx = POWDER;
                end else begin
                    state_nx = HEAT;
                end
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = GRIND;
            end
        end
        POWDER: begin
            if(counter_ff >= POWDER_CYCLES) begin
                counter_nx = 0;
                state_nx   = POUR;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = POUR;
            end
        end
        HEAT: begin
            if(counter_ff >= heat_delay_ff) begin
                counter_nx = 0;
                if(|operation_sel_ff[1:0]) begin
                    state_nx = POWDER;
                end else begin
                    state_nx = POUR;
                end
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = HEAT;
            end
        end
        POUR: begin
            if(counter_ff >= pour_delay_ff) begin
                counter_nx = 0;
                state_nx   = IDLE;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = POUR;
            end
        end
        default: begin
            counter_nx = 0;
            state_nx   = IDLE;
        end
    endcase
end

// ----------------------------------------
// - Controller outputs
// ----------------------------------------
always_comb begin
    case(state_ff)
        IDLE: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_use_powder    = 1'b0;
            o_grind_beans   = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        BEAN_SEL: begin
            o_bean_sel                      = 1'b0; // Set all bits to 0
            o_bean_sel[bean_sel_in_ff]      = 1'b1; // Only the position of bean_sel_ff should be 1
            o_grind_beans                   = 1'b0;
            o_use_powder                    = 1'b0;
            o_heat_water                    = 1'b0;
            o_pour_coffee                   = 1'b0;
        end
        GRIND: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b1;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        POWDER: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b1;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        HEAT: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b1;
            o_pour_coffee   = 1'b0;
        end
        POUR: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b1;
        end
        default: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
    endcase
end

endmodule : coffee_machine

