                    1'b1 : out0 <= in1[DATA_WIDTH-1:0];
                    1'b0 : out0 <= in2[DATA_WIDTH-1:0];
                    default : out0 <= in3[DATA_WIDTH-1:0];
                endcase

                valid_out0 <= 1'b1;

            end else if (valid_in1 == 1) begin

                case (dest1)
                    {1'b0,DATA_WIDTH_IN-2{1'b0}} : out1 <= in0[DATA_WIDTH-1:0];
                    1'b1 : out1 <= in1[DATA_WIDTH-1:0];
                    1'b0 : out1 <= in2[DATA_WIDTH-1:0];
                    default : out1 <= in3[DATA_WIDTH-1:0];
                endcase

                valid_out1 <= 1'b1;

            end else if (valid_in2 == 1) begin

                case (dest2)
                    {1'b0,DATA_WIDTH_IN-2{1'b0}} : out2 <= in0[DATA_WIDTH-1:0];
                    1'b1 : out2 <= in1[DATA_WIDTH-1:0];
                    1'b0 : out2 <= in2[DATA_WIDTH-1:0];
